import { db } from "./firebase";
import { ref, push, set, get, child, query, orderByChild, equalTo } from "firebase/database";
import { CommunicationLog, VendorActionStatus } from "@/types";

const COMMUNICATIONS_COLLECTION = "communications";
const VENDOR_ACTIONS_COLLECTION = "vendorActions";

/**
 * Log a new communication (email, call, note, meeting)
 */
export const logCommunication = async (log: Omit<CommunicationLog, 'id'>): Promise<string> => {
    try {
        const commRef = ref(db, COMMUNICATIONS_COLLECTION);
        const newCommRef = push(commRef);

        await set(newCommRef, {
            ...log,
            timestamp: log.timestamp.toISOString()
        });

        return newCommRef.key!;
    } catch (error) {
        console.error("Error logging communication:", error);
        throw error;
    }
};

/**
 * Get all communication logs for a specific PO
 */
export const getCommunicationHistory = async (poId: string): Promise<CommunicationLog[]> => {
    try {
        const dbRef = ref(db);
        const commQuery = query(
            child(dbRef, COMMUNICATIONS_COLLECTION),
            orderByChild('poId'),
            equalTo(poId)
        );

        const snapshot = await get(commQuery);

        if (snapshot.exists()) {
            const data = snapshot.val();
            return Object.entries(data).map(([key, v]: [string, any]) => ({
                id: key,
                ...v,
                timestamp: new Date(v.timestamp),
                readReceipt: v.readReceipt ? new Date(v.readReceipt) : undefined
            })) as CommunicationLog[];
        }
        return [];
    } catch (error) {
        console.error("Error fetching communication history:", error);
        return [];
    }
};

/**
 * Mark a communication as read
 */
export const markCommunicationAsRead = async (logId: string): Promise<void> => {
    try {
        const commRef = ref(db, `${COMMUNICATIONS_COLLECTION}/${logId}`);
        await set(commRef, {
            readReceipt: new Date().toISOString()
        });
    } catch (error) {
        console.error("Error marking communication as read:", error);
        throw error;
    }
};

/**
 * Calculate vendor action status for a PO
 */
export const getVendorActionStatus = async (poId: string): Promise<VendorActionStatus | null> => {
    try {
        const history = await getCommunicationHistory(poId);

        if (history.length === 0) {
            return {
                poId,
                status: 'PENDING_ACKNOWLEDGMENT',
                escalationLevel: 0
            };
        }

        // Sort by timestamp descending
        const sortedHistory = history.sort((a, b) =>
            new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
        );

        const lastContact = sortedHistory[0];
        const lastContactDate = new Date(lastContact.timestamp);
        const now = new Date();
        const daysSinceLastContact = Math.floor((now.getTime() - lastContactDate.getTime()) / (1000 * 60 * 60 * 24));

        // Determine status based on communication history
        const hasAcknowledgment = history.some(log =>
            log.type === 'EMAIL' && log.subject.toLowerCase().includes('acknowledged')
        );

        let status: VendorActionStatus['status'] = 'PENDING_ACKNOWLEDGMENT';
        let escalationLevel: 0 | 1 | 2 | 3 = 0;

        if (hasAcknowledgment) {
            status = 'ACKNOWLEDGED';
        } else if (daysSinceLastContact > 7) {
            status = 'OVERDUE';
            escalationLevel = 3;
        } else if (daysSinceLastContact > 3) {
            status = 'OVERDUE';
            escalationLevel = 2;
        } else if (daysSinceLastContact > 1) {
            escalationLevel = 1;
        }

        return {
            poId,
            status,
            lastContact: lastContactDate,
            responseDeadline: new Date(lastContactDate.getTime() + (2 * 24 * 60 * 60 * 1000)), // 2 days
            escalationLevel,
            daysSinceLastContact
        };
    } catch (error) {
        console.error("Error calculating vendor action status:", error);
        return null;
    }
};

/**
 * Save vendor action status
 */
export const saveVendorActionStatus = async (status: VendorActionStatus): Promise<void> => {
    try {
        const statusRef = ref(db, `${VENDOR_ACTIONS_COLLECTION}/${status.poId}`);
        await set(statusRef, {
            ...status,
            lastContact: status.lastContact?.toISOString(),
            responseDeadline: status.responseDeadline?.toISOString()
        });
    } catch (error) {
        console.error("Error saving vendor action status:", error);
        throw error;
    }
};

/**
 * Get all pending vendor actions (for dashboard widget)
 */
export const getPendingVendorActions = async (): Promise<VendorActionStatus[]> => {
    try {
        const dbRef = ref(db);
        const snapshot = await get(child(dbRef, VENDOR_ACTIONS_COLLECTION));

        if (snapshot.exists()) {
            const data = snapshot.val();
            return Object.values(data).map((v: any) => ({
                ...v,
                lastContact: v.lastContact ? new Date(v.lastContact) : undefined,
                responseDeadline: v.responseDeadline ? new Date(v.responseDeadline) : undefined
            })) as VendorActionStatus[];
        }
        return [];
    } catch (error) {
        console.error("Error fetching pending vendor actions:", error);
        return [];
    }
};
